import { memo, useId } from "react";
import { User } from "lucide-react";
import { cn } from "@/lib/utils";
import { AuthorAvatar } from "./parts/avatar";
import { resolveTone } from "./parts/tone-resolver";
import { AUTHOR_CARD_DEFAULT_LABELS, type AuthorCard01Props } from "./types";

function AuthorCard01Inner(props: AuthorCard01Props) {
  const {
    name,
    role,
    bio,
    imageSrc,
    imageAlt,
    fallbackIcon = User,
    href,
    linkComponent,
    tone = "primary",
    headingAs: HeadingTag = "h3",
    labels,
    className,
    headingClassName,
    nameClassName,
    bioClassName,
  } = props;

  const nameId = useId();
  const toneClasses = resolveTone(tone);
  const resolvedLabels = { ...AUTHOR_CARD_DEFAULT_LABELS, ...labels };
  const resolvedAlt = imageAlt ?? name;

  const isClickable = Boolean(href);
  const RootEl = isClickable ? linkComponent ?? "a" : "div";

  const rootClass = cn(
    "block bg-card rounded-2xl p-6 border border-border/50 transition-colors",
    isClickable &&
      "hover:border-border focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
    className
  );

  const linkProps = isClickable
    ? { href, "aria-labelledby": nameId }
    : {};

  return (
    <RootEl className={rootClass} {...linkProps}>
      <HeadingTag
        className={cn(
          "text-lg font-serif font-bold text-foreground mb-4",
          headingClassName
        )}
      >
        {resolvedLabels.heading}
      </HeadingTag>

      <div className="flex items-center gap-4">
        <AuthorAvatar
          imageSrc={imageSrc}
          imageAlt={resolvedAlt}
          fallbackIcon={fallbackIcon}
          toneClasses={toneClasses}
        />
        <div>
          <p
            id={nameId}
            className={cn("font-semibold text-foreground", nameClassName)}
          >
            {name}
          </p>
          <p className="text-sm text-muted-foreground">{role}</p>
        </div>
      </div>

      {bio ? (
        <p className={cn("text-sm text-muted-foreground mt-4", bioClassName)}>
          {bio}
        </p>
      ) : null}
    </RootEl>
  );
}

export const AuthorCard01 = memo(AuthorCard01Inner);
AuthorCard01.displayName = "AuthorCard01";

export { AuthorCard01 } from "./author-card-01";
export {
  AUTHOR_CARD_DEFAULT_LABELS,
  type AuthorCard01Labels,
  type AuthorCard01Props,
  type AuthorCardTone,
} from "./types";
export { meta } from "./meta";

import type { ComponentType, ElementType } from "react";

export type AuthorCardTone = "primary" | "accent" | "muted";

export interface AuthorCard01Labels {
  heading?: string;
}

export interface AuthorCard01Props {
  name: string;
  role: string;
  bio?: string;
  imageSrc?: string;
  imageAlt?: string;
  fallbackIcon?: ComponentType<{ className?: string }>;
  href?: string;
  linkComponent?: ElementType;
  tone?: AuthorCardTone;
  headingAs?: "h2" | "h3" | "h4";
  labels?: AuthorCard01Labels;
  className?: string;
  headingClassName?: string;
  nameClassName?: string;
  bioClassName?: string;
}

export const AUTHOR_CARD_DEFAULT_LABELS: Required<AuthorCard01Labels> = {
  heading: "About the author",
};

import type { ComponentType } from "react";
import { cn } from "@/lib/utils";
import type { ToneClasses } from "./tone-resolver";

interface AuthorAvatarProps {
  imageSrc?: string;
  imageAlt: string;
  fallbackIcon: ComponentType<{ className?: string }>;
  toneClasses: ToneClasses;
}

export function AuthorAvatar({
  imageSrc,
  imageAlt,
  fallbackIcon: Icon,
  toneClasses,
}: AuthorAvatarProps) {
  if (imageSrc) {
    return (
      <img
        src={imageSrc}
        alt={imageAlt}
        loading="lazy"
        className="w-16 h-16 rounded-full object-cover shrink-0"
      />
    );
  }
  return (
    <div
      className={cn(
        "w-16 h-16 rounded-full flex items-center justify-center shrink-0",
        toneClasses.avatarBg
      )}
      aria-hidden="true"
    >
      <Icon className={cn("w-8 h-8", toneClasses.avatarIcon)} />
    </div>
  );
}

import type { AuthorCardTone } from "../types";

export interface ToneClasses {
  avatarBg: string;
  avatarIcon: string;
}

const TONE_MAP: Record<AuthorCardTone, ToneClasses> = {
  primary: { avatarBg: "bg-primary/10", avatarIcon: "text-primary" },
  accent: { avatarBg: "bg-accent", avatarIcon: "text-accent-foreground" },
  muted: { avatarBg: "bg-muted", avatarIcon: "text-muted-foreground" },
};

export function resolveTone(tone: AuthorCardTone): ToneClasses {
  return TONE_MAP[tone];
}
